    var stack []rune
    pairs := map[rune]rune{')': '(', ']': '[', '}': '{'}
    for _, ch := range s {
        if open, ok := pairs[ch]; ok {
            top := stack[len(stack)-1]
            if top != open { return false }
            stack = stack[:len(stack)-1]
        } else {
            stack = append(stack, ch)
        }
    }
    return len(stack) == 0
}
